use soroban_sdk::{contract, contractimpl, Address, Env, Bytes};

#[contractimpl]
impl SafeUpgradableContract {
    // SAFE: upgrade with admin.require_auth
    pub fn safe_upgrade(env: Env, admin: Address, new_wasm: Bytes) {
        admin.require_auth();
        env.deployer().upload_contract_wasm(&new_wasm);
    }

    // SAFE: update_contract with only_admin
    pub fn safe_update(env: Env, caller: Address, new_wasm: Bytes) {
        only_admin(&env, &caller);
        env.deployer().upload_contract_wasm(&new_wasm);
    }

    // SAFE: set_wasm with assert_admin
    pub fn safe_set_wasm(env: Env, admin: Address, code: Bytes) {
        assert_admin(&env, &admin);
        env.deployer().upload_contract_wasm(&code);
    }

    pub fn get_version(env: Env) -> u32 {
        1
    }
}
